  ('optometrist-moex-00751', 'optometrist', 'optometrist-moex-112-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有一患者鏡框配製完成時，鏡框框面的鏡片會緊貼在患者睫毛上，造成鏡框上的光學鏡片會與睫毛產 生摩擦，造成患者睫毛的敏感不舒服，若要改善患者配戴時所產生睫毛摩擦鏡片後表面，則要使用何 種方式來改善此患者不舒適的狀況？', '["增加前傾角", "增加鏡框彎弧", "減少鼻墊臂的有效長度", "調寬鼻墊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:43+00:00", "source_pdf_sha1": "168693ccce30", "answer_pdf_sha1": "ebe875537b15", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
